int partition(int arr[], int s, int e) {
    int pivot = arr[e];
    int p_index = s;

    for (int i = s; i < e; i++) {
        if (arr[i] < pivot) {
            int temp = arr[i];
            arr[i] = arr[p_index];
            arr[p_index] = temp;
            p_index++;
        }
    }

    int temp = arr[e];
    arr[e] = arr[p_index];
    arr[p_index] = temp;

    return p_index;
}

